    .map((line) => line.slice(2).trim().toLowerCase());
  const allowed = new Set(allowedValues.map((value) => value.toLowerCase()));
  return {
    values: bulletValues,
    invalid: bulletValues.filter((value) => !allowed.has(value)),
  };
}

